#include <iostream>
#include <string>

using namespace std;

int main() {
    char start;
    cin >> start;

    for (char end = start; end <= 'Z'; ++end) {
        for (char c = start; c <= end; ++c) {
            cout << c;
        }
        cout << '\n';
    }

    return 0;
}
